from dataclasses import dataclass
from typing import Literal

AlertSource = Literal["pagerduty", "grafana", "zoom", "notion", "status_page"]

@dataclass
class WarRoomEvent:
    source: AlertSource
    event_type: str
    incident_id: str
    payload: dict

def handle_warroom_event(event: WarRoomEvent) -> str | None:
    """
    Route incoming webhook events to the correct bridge channel action.
    Returns the Slack message posted, or None if no action needed.
    """
    bridge = f"inc-{event.incident_id}"

    if event.source == "pagerduty":
        if event.event_type == "acknowledged":
            return post_to_channel(bridge,  # noqa: F821
                f":white_check_mark: PD page acknowledged by {event.payload['responder']}")
        if event.event_type == "escalated":
            return post_to_channel(bridge,
                f":rotating_light: PD escalated to {event.payload['escalation_policy']}")

    elif event.source == "grafana":
        if event.event_type == "alert_firing":
            metric = event.payload["metric"]
            value = event.payload["value"]
            return post_to_channel(bridge,
                f":chart_with_upwards_trend: Grafana alert: {metric} = {value}")
        if event.event_type == "alert_resolved":
            return post_to_channel(bridge,
                f":large_green_circle: Grafana alert resolved: {event.payload['metric']}")

    elif event.source == "zoom":
        if event.event_type == "recording_ready":
            return post_to_channel(bridge,
                f":film_projector: Bridge recording ready: {event.payload['url']}")

    return None
